// Run an op, expect a single result whose key may be specified.
KeyVal Backend::op1(
    QString cmd, QStringList data, QString key)
{
    auto results = op(cmd, data);
    if (results.length() == 1) {
        auto kv = results[0];
        if (key.isEmpty() || key == kv.key)
            return kv;
    }
    return {};
}
